/** One tintable pip glyph. "square" isn't drawn here — the caller renders a
 * plain filled block for it (see ResourceTile). All game-icons.net source
 * icons share a 0 0 512 512 viewBox. */
export function ResourceIcon({
  icon,
  color,
  size = 20,
}: {
  icon: string;
  color: string;
  size?: number;
}) {
  const d = ICON_PATHS[icon as Exclude<IconKey, "square">];
  if (!d) return null;
  return (
    <svg width={size} height={size} viewBox="0 0 512 512" fill="none" aria-hidden="true">
      <path d={d} fill={color} fillRule="evenodd" clipRule="evenodd" />
    </svg>
  );
}

/**
 * How many pip-columns a tile should lay out in, driven by the resource's
 * own max — small pools (Ki, max 3) get a small/narrow tile, large pools
 * (Sorcery Points, max 20) get a wider one, recomputed live whenever `max`
 * changes. Roughly square-ish rather than one tall single column.
 */
export function pipColsForMax(max: number): number {
  return Math.min(6, Math.max(1, Math.ceil(Math.sqrt(max))));
}
